"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[903860],{58841:e=>{e.exports=JSON.parse('{"tag":{"label":"water","permalink":"/dst-api-webdocs/docs/tags/water","allTagsPath":"/dst-api-webdocs/docs/tags","count":23,"items":[{"id":"game-scripts/prefabs/boat","title":"Boat","description":"Manages the creation, behavior, and physics of ocean-going vessels, including variant-specific functionality (wood, grass, ice, pirate, ancient, otterden).","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boat"},{"id":"game-scripts/components/boatleak","title":"Boatleak","description":"Manages visual, audio, and state transitions for boat leaks and repairs in DST, including plugged/unplugged states, repair timers, and integration with HullHealth for dynamic leak tracking.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatleak"},{"id":"game-scripts/components/boatphysics","title":"Boatphysics","description":"Manages boat movement, physics, steering, sail/magnet forces, drag, and collision response for watercraft entities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatphysics"},{"id":"game-scripts/components/boattrail","title":"Boattrail","description":"Generates visual water wake effects behind a boat entity as it moves.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boattrail"},{"id":"game-scripts/components/fishable","title":"Fishable","description":"Manages a pool of fish that can be caught via fishing mechanics, including respawning, freezing states, and hooking/release logic.","permalink":"/dst-api-webdocs/docs/game-scripts/components/fishable"},{"id":"game-scripts/components/floater","title":"Floater","description":"Manages visual and behavioral effects when an entity enters or remains in water, including wetness application, splash spawning, and floating animations.","permalink":"/dst-api-webdocs/docs/game-scripts/components/floater"},{"id":"game-scripts/components/flotationdevice","title":"Flotationdevice","description":"Prevents drowning damage and optionally executes custom logic when drowning is prevented.","permalink":"/dst-api-webdocs/docs/game-scripts/components/flotationdevice"},{"id":"game-scripts/prefabs/grassgator","title":"Grassgator","description":"Manages the behavior, stats, movement, and state persistence of the Grassgator entity in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/grassgator"},{"id":"game-scripts/prefabs/grotto_pool_small","title":"Grotto Pool Small","description":"Creates a small, non-networked decorative pool entity with visual effects, light emission, and interaction with the grotto waterfall system.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/grotto_pool_small"},{"id":"game-scripts/prefabs/hotspring","title":"Hotspring","description":"Represents a dynamic thermal pool entity that provides health and sanity restoration to occupants, can be transformed into a calcified glass state via bath bombs or full moon cycles, and yields loot when mined after calcification.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hotspring"},{"id":"game-scripts/prefabs/oar","title":"Oar","description":"Provides the logic and configuration for oar items used in boat rowing, including durability tracking, waterproofing, and attachment to entities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oar"},{"id":"game-scripts/prefabs/oasislake","title":"Oasislake","description":"Represents a dynamic water source in the Desert biome that can dry up during sandstorms and regrow vegetation afterward.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oasislake"},{"id":"game-scripts/prefabs/ocean_trawler","title":"Ocean Trawler","description":"A deployable water-based fishing structure that catches and stores fish, with state-aware perish rate scaling and overflow fish release on destruction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ocean_trawler"},{"id":"game-scripts/prefabs/oceanfish_shoalspawner","title":"Oceanfish Shoalspawner","description":"Spawns and manages a shoal of medium-sized oceanfish entities in water regions, automatically regenerating and respawning fish over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanfish_shoalspawner"},{"id":"game-scripts/components/oceanthrowable","title":"Oceanthrowable","description":"Manages the attachment and configuration of the complexprojectile component for entities intended to be thrown into ocean water.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanthrowable"},{"id":"game-scripts/prefabs/oceanwhirlportal","title":"Oceanwhirlportal","description":"A portal prefab that teleports boats and their contents between distant ocean locations while applying protective effects and generating wake waves.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanwhirlportal"},{"id":"game-scripts/prefabs/otter","title":"Otter","description":"A hostile ocean-dwelling monster that steals items, shares combat targets with nearby allies, and drops loot upon death.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/otter"},{"id":"game-scripts/prefabs/quagmire_pond","title":"Quagmire Pond","description":"A static environmental object representing a salt pond in the Quagmire biome that acts as a water source and obstacle.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_pond"},{"id":"game-scripts/prefabs/schoolherd","title":"Schoolherd","description":"Manages a school of fish that moves between pre-defined navigation points and reacts to entity sleep states.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/schoolherd"},{"id":"game-scripts/brains/sharkboi_waterbrain","title":"Sharkboi Waterbrain","description":"Defines the behavior tree for the Sharkboi entity when submerged in water, primarily using a simple wander task.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/sharkboi_waterbrain"},{"id":"game-scripts/components/waterphysics","title":"Waterphysics","description":"Applies basic physical properties to entities that interact with water, specifically defining their bounciness (restitution).","permalink":"/dst-api-webdocs/docs/game-scripts/components/waterphysics"},{"id":"game-scripts/components/watersource","title":"Watersource","description":"Manages the presence of the \\"watersource\\" tag on an entity based on availability state.","permalink":"/dst-api-webdocs/docs/game-scripts/components/watersource"},{"id":"game-scripts/prefabs/wave_shimmer","title":"Wave Shimmer","description":"Creates visual shimmer wave effects in ocean water using pre-defined animation assets.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wave_shimmer"}],"unlisted":false}}')}}]);